class Solution {
    public int minLength(String s) {
        int countAB = 0;
        int countCD = 0;
        for (int i = 0; i < s.length() - 1; i++) {
            if (s.substring(i, i + 2).equals("AB")) {
                countAB++;
            }
            if (s.substring(i, i + 2).equals("CD")) {
                countCD++;
            }
        }
        return s.length() - countAB * 2 - countCD * 2;
    }
}
